import React, { Component } from 'react';
import { styled, createTheme, ThemeProvider } from '@mui/material/styles';
import {
  CssBaseline,
  Box,
  AppBar as MuiAppBar,
  Toolbar,
  Link,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Button,
  Tab,
  Tabs,TextField
} from '@mui/material';

const AppBar = styled(MuiAppBar)(({ theme }) => ({
  zIndex: theme.zIndex.drawer + 1,
}));

const defaultTheme = createTheme();

export default class Dashboard extends Component {
  constructor(props) {
    super(props);
    this.state = {
      isNightMode: false,
      selectedTab: 'All', // Default selected tab
      name: '',
      email: '',
      message: '',
      projects: {
        All: [
          { title: 'Project 1', description: 'All projects description.', link: 'https://github.com/yourusername/project1' },
          { title: 'Project 2', description: 'All projects description.', link: 'https://github.com/yourusername/project2' },
        ],
        'WEB APPS': [
          { title: 'Web App 1', description: 'A full-stack web application built with React, Node.js, and MongoDB.', link: 'https://github.com/yourusername/webapp1' },
        ],
        'ANDROID APPS': [
          { title: 'Android App 1', description: 'An Android app developed using Java and Kotlin.', link: 'https://github.com/yourusername/androidapp1' },
        ],
        'MACHINE LEARNING MODELS': [
          { title: 'ML Model 1', description: 'A machine learning model for data prediction built using Python and Scikit-learn.', link: 'https://github.com/yourusername/mlmodel1' },
        ],
        GAMES: [
          { title: 'Game 1', description: 'A simple 2D game built using Unity.', link: 'https://github.com/yourusername/game1' },
        ],
        'SELENIUM PROJECTS': [
          { title: 'Selenium Project 1', description: 'A web automation project built using Selenium.', link: 'https://github.com/yourusername/seleniumproject1' },
        ],
        'WEB3/BLOCKCHAIN APPS': [
          { title: 'Blockchain App 1', description: 'A decentralized application built using Ethereum and Web3.js.', link: 'https://github.com/yourusername/blockchainapp1' },
        ],
        'CHROME EXTENSIONS': [
          { title: 'Chrome Extension 1', description: 'A Chrome extension that enhances browser functionality.', link: 'https://github.com/yourusername/chromeextension1' },
        ]
      }
    };
  }

  toggleTheme = () => {
    this.setState((prevState) => ({
      isNightMode: !prevState.isNightMode,
    }));
  };

  handleTabChange = (event, newValue) => {
    this.setState({ selectedTab: newValue });
  };

  handleChange = (e) => {
    this.setState({ [e.target.name]: e.target.value });
  };

  handleSubmit = (e) => {
    e.preventDefault();
    // Handle form submission logic here
    console.log('Form submitted:', this.state);
  };

  render() {
    const { isNightMode, selectedTab, projects, name, email, message } = this.state;

    return (
      <ThemeProvider theme={defaultTheme}>
        <CssBaseline />
        <Box
          sx={{
            display: 'flex',
            flexDirection: 'column',
            height: '100vh',
            backgroundColor: isNightMode ? '#333' : '#fff',
            color: isNightMode ? '#fff' : '#000',
            padding: 2,
          }}
        >
          <AppBar position="absolute">
            <Toolbar component="nav" variant="dense" sx={{ justifyContent: 'space-between', overflowX: 'auto' }}>
              <Typography variant="h6" sx={{ fontWeight: 'bold' }}>My Portfolio</Typography>
              <Button onClick={this.toggleTheme} variant="contained" color="primary">
                {isNightMode ? 'Switch to Day Mode' : 'Switch to Night Mode'}
              </Button>
            </Toolbar>
          </AppBar>

          <Box component="main" sx={{ flexGrow: 1, overflow: 'auto', padding: 2 }}>
            <Container id="home" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h2" gutterBottom sx={{ fontWeight: 'bold' }}>
                Welcome to My Portfolio
              </Typography>
              <Typography variant="h5">
                I am a passionate web developer specializing in React.js and React Native.
              </Typography>
            </Container>

            {/* Project Tabs */}
            <Container id="projects" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom>
                Projects
              </Typography>

              <Tabs
                value={selectedTab}
                onChange={this.handleTabChange}
                aria-label="Project categories"
                indicatorColor="primary"
                textColor="primary"
                centered
              >
                {[
                  'All', 'WEB APPS', 'ANDROID APPS', 'MACHINE LEARNING MODELS', 
                  'GAMES', 'SELENIUM PROJECTS', 'WEB3/BLOCKCHAIN APPS', 'CHROME EXTENSIONS'
                ].map((tab) => (
                  <Tab
                    key={tab}
                    value={tab}
                    label={tab}
                    sx={{
                      backgroundColor: selectedTab === tab ? 'tomato' : 'gray',
                      color: selectedTab === tab ? 'white' : 'black',
                      fontWeight: 'bold',
                      borderRadius: '5px',
                    }}
                  />
                ))}
              </Tabs>

              {/* Render projects based on selected tab */}
              <Grid container spacing={2}>
                {projects[selectedTab].map((project, index) => (
                  <Grid item xs={12} sm={6} md={4} key={index}>
                    <Card>
                      <CardContent>
                        <Typography variant="h5">{project.title}</Typography>
                        <Typography variant="body2">{project.description}</Typography>
                        <Button href={project.link} target="_blank" variant="contained" color="primary" sx={{ mt: 2 }}>
                          View Project
                        </Button>
                      </CardContent>
                    </Card>
                  </Grid>
                ))}
              </Grid>
            </Container>

            {/* Contact Section */}
            <Container id="contact" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom>
                Contact Me
              </Typography>
              <form onSubmit={this.handleSubmit}>
                <TextField
                  label="Name"
                  name="name"
                  value={name}
                  onChange={this.handleChange}
                  fullWidth
                  required
                  sx={{ mb: 2 }}
                />
                <TextField
                  label="Email"
                  name="email"
                  type="email"
                  value={email}
                  onChange={this.handleChange}
                  fullWidth
                  required
                  sx={{ mb: 2 }}
                />
                <TextField
                  label="Message"
                  name="message"
                  value={message}
                  onChange={this.handleChange}
                  multiline
                  rows={4}
                  fullWidth
                  required
                  sx={{ mb: 2 }}
                />
                <Button type="submit" variant="contained" color="primary">
                  Send Message
                </Button>
              </form>
            </Container>
          </Box>
        </Box>
      </ThemeProvider>
    );
  }
}
